```class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int maxScore = 0;
        List<Integer> res = new ArrayList<>();
        for (int i = 0; i <= n; i++) {
            int leftOnes = 0, rightZeros = 0;
            for (int j = 0; j < i; j++) {
                if (nums[j] == 1) leftOnes++;
            }
            for (int j = i; j < n; j++) {
                if (nums[j] == 0) rightZeros++;
            }
            int score = leftOnes + rightZeros;
            if (score > maxScore) {
                maxScore = score;
                res.clear();
                res.add(i);
            } else if (score == maxScore) {
                res.add(i);
            }
        }
        return res;
    }
}```
